package com.example.bankingapp;

import android.os.Bundle;
import android.widget.TextView;
import androidx.appcompat.app.AppCompatActivity;
import java.text.NumberFormat;
import java.util.Locale;

public class MainActivity extends AppCompatActivity {

    private double accountBalance = 1000.00; // Initial balance
    private TextView balanceTextView;

    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);

        balanceTextView = findViewById(R.id.balanceTextView);
        displayBalance();
    }

    private void displayBalance() {
        NumberFormat currencyFormat = NumberFormat.getCurrencyInstance(Locale.getDefault());
        balanceTextView.setText(currencyFormat.format(accountBalance));
    }

    public boolean processTransaction(double amount, boolean isCredit) {
        if (isCredit) {
            accountBalance += amount;
            displayBalance();
            return true;
        } else {
            if (accountBalance >= amount) {
                accountBalance -= amount;
                displayBalance();
                return true;
            } else {
                // Insufficient funds
                return false;
            }
        }
    }
}

package com.example.bankingapp.security;

import java.security.MessageDigest;
import java.security.NoSuchAlgorithmException;

public class SecurityUtils {

    public static String hashTransaction(String transactionDetails) {
        try {
            MessageDigest digest = MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(transactionDetails.getBytes());
            StringBuilder hexString = new StringBuilder();
            for (byte b : hash) {
                String hex = Integer.toHexString(0xff & b);
                if (hex.length() == 1) hexString.append('0');
                hexString.append(hex);
            }
            return hexString.toString();
        } catch (NoSuchAlgorithmException e) {
            throw new RuntimeException(e);
        }
    }
}